// ==================== Token Utilities ====================
function parseHashFragment(hash) {
  if (!hash || hash.length <= 1) return {};

  const fragment = hash.substring(1); // Remove the leading '#'
  const params = {};

  fragment.split('&').forEach((pair) => {
    const [key, value] = pair.split('=');
    if (key) {
      params[decodeURIComponent(key)] = decodeURIComponent(value || '');
    }
  });

  return params;
}

function generateRandomState() {
  const array = new Uint8Array(32);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, '0')).join('');
}

function generateNonce() {
  const array = new Uint8Array(16);
  crypto.getRandomValues(array);
  return Array.from(array, (byte) => byte.toString(16).padStart(2, '0')).join('');
}

function storeToken(tokenData) {
  const storageData = {
    access_token: tokenData.access_token,
    token_type: tokenData.token_type || 'Bearer',
    expires_in: tokenData.expires_in,
    scope: tokenData.scope,
    stored_at: Date.now(),
    expires_at: tokenData.expires_in
      ? Date.now() + parseInt(tokenData.expires_in, 10) * 1000
      : null,
  };
  sessionStorage.setItem('oauth_token_data', JSON.stringify(storageData));
  return storageData;
}

function getStoredToken() {
  const raw = sessionStorage.getItem('oauth_token_data');
  if (!raw) return null;

  try {
    const tokenData = JSON.parse(raw);

    // Check expiration
    if (tokenData.expires_at && Date.now() >= tokenData.expires_at) {
      clearStoredToken();
      return null;
    }

    return tokenData;
  } catch {
    clearStoredToken();
    return null;
  }
}

function clearStoredToken() {
  sessionStorage.removeItem('oauth_token_data');
  sessionStorage.removeItem('oauth_state');
  sessionStorage.removeItem('oauth_nonce');
}

function buildAuthorizationUrl() {
  const state = generateRandomState();
  const nonce = generateNonce();

  // Store state and nonce for verification
  sessionStorage.setItem('oauth_state', state);
  sessionStorage.setItem('oauth_nonce', nonce);

  const params = new URLSearchParams({
    response_type: OAUTH_CONFIG.responseType,
    client_id: OAUTH_CONFIG.clientId,
    redirect_uri: OAUTH_CONFIG.redirectUri,
    scope: OAUTH_CONFIG.scope,
    state: state,
    nonce: nonce,
  });

  return `${OAUTH_CONFIG.authorizationEndpoint}?${params.toString()}`;
}

function decodeJwtPayload(token) {
  try {
    const base64Url = token.split('.')[1];
    const base64 = base64Url.replace(/-/g, '+').replace(/_/g, '/');
    const jsonPayload = decodeURIComponent(
      atob(base64)
        .split('')
        .map((c) => '%' + ('00' + c.charCodeAt(0).toString(16)).slice(-2))
        .join('')
    );
    return JSON.parse(jsonPayload);
  } catch {
    return null;
  }
}

