// Protected Route wrapper
function ProtectedRoute({ children, navigate }) {
  const { isAuthenticated, isLoading } = useAuth();

  useEffect(() => {
    if (!isLoading && !isAuthenticated) {
      navigate('/');
    }
  }, [isAuthenticated, isLoading, navigate]);

  if (isLoading) {
    return React.createElement(
      'div',
      { style: styles.container },
      React.createElement(
        'div',
        { style: styles.card },
        React.createElement('div', { style: styles.spinner }),
        React.createElement('p', { style: styles.text }, 'Loading...')
      )
    );
  }

  if (!isAuthenticated) {
    return null;
  }

  return children;
}

// ==================== Main App ====================
function App() {
  const { path, navigate } = useRoute();
  const { isAuthenticated } = useAuth();

  let content;

  switch (path) {
    case '/callback':
      content = React.createElement(CallbackPage, { navigate });
      break;
    case '/dashboard':
      content = React.createElement(
        ProtectedRoute,
        { navigate },
        React.createElement(DashboardPage, { navigate })
      );
      break;
    case '/':
    default:
      if (isAuthenticated) {
        content = React.createElement(DashboardPage, { navigate });
      } else {
        content = React.createElement(LoginPage, null);
      }
      break;
  }

  return React.createElement(
    'div',
    { style: styles.app },
    // Navigation bar
    React.createElement(
      'nav',
      { style: styles.nav },
      React.createElement(
        'div',
        { style: styles.navContent },
        React.createElement(
          'span',
          { style: styles.navBrand },
          '🔐 OAuth SPA'
        ),
        React.createElement(
          'div',
          { style: styles.navLinks },
          React.createElement(
            'button',
            {
              style: styles.navLink,
              onClick: () => navigate('/'),
            },
            'Home'
          ),
          isAuthenticated &&
            React.createElement(
              'button',
              {
                style: styles.navLink,
                onClick: () => navigate('/dashboard'),
              },
              'Dashboard'
            ),
          React.createElement(
            'span',
            {
              style: {
                ...styles.statusBadge,
                backgroundColor: isAuthenticated ? '#27ae60' : '#e74c3c',
              },
            },
            isAuthenticated ? '● Authenticated' : '○ Not Authenticated'
          )
        )
      )
    ),
    // Main content
    content
  );
}

